mapper.select:
SELECT t.*, u.username
FROM forum_topic t
LEFT JOIN forum_user u ON t.user_id = u.id
WHERE t.status != 'deleted'

    AND t.title LIKE CONCAT('%', #{title}, '%')


    AND t.category = #{category}


    AND t.created_at >= #{startTime}


    AND t.created_at <= #{endTime}

ORDER BY t.created_at DESC

SELECT EXISTS(
    SELECT 1 FROM forum_favorite
    WHERE user_id = #{userId} AND topic_id = #{topicId}
)

mapper.update:
UPDATE forum_topic
SET favorites_count = #{favoritesCount}
WHERE id = #{id}

UPDATE forum_topic
SET view_count = #{viewCount}
WHERE id = #{id}

